module four_bit_adder (
    input [3:0] A,
    input [3:0] B,
    output [3:0] S,
    output C_out
);
    wire [4:0] temp; // to hold the carry

      wire _n01 = A[0] ^ B[0];
  wire _c01 = A[0] & B[0];
  wire _n02 = A[1] ^ B[1] ^ _c01;
  wire _c02 = (A[1] & B[1]) | (A[1] & _c01) | (B[1] & _c01);
  wire _n03 = A[2] ^ B[2] ^ _c02;
  wire _c03 = (A[2] & B[2]) | (A[2] & _c02) | (B[2] & _c02);
  wire _n04 = A[3] ^ B[3] ^ _c03;
  wire _c04 = (A[3] & B[3]) | (A[3] & _c03) | (B[3] & _c03);
  assign temp = {_n01, _n02, _n03, _n04}; // sum the inputs, including carry
    assign S = temp[3:0]; // the lower 4 bits are the sum
    assign C_out = temp[4]; // the carry out is the 5th bit
endmodule
